// ---- Composable function basics ----
// In a real Android project, you'd need these imports:
// import androidx.compose.runtime.Composable
// import androidx.compose.material3.Text
// import androidx.compose.ui.Modifier
// import androidx.compose.ui.tooling.preview.Preview

// ---- Basic Composable ----
@Composable
fun Greeting(name: String) {
    Text(text = "Hello, $name!")
}

// ---- Composable with multiple elements ----
@Composable
fun WelcomeScreen(name: String) {
    Column {
        Text(text = "Welcome to Kotlin-chan!")
        Text(text = "Hello, $name!")
        Text(text = "Let's learn Jetpack Compose.")
    }
}

// ---- Composable with modifiers ----
@Composable
fun StyledText(name: String) {
    Text(
        text = "Hello, $name!",
        modifier = Modifier
            .padding(16.dp)
            .fillMaxWidth(),
        fontSize = 24.sp,
        fontWeight = FontWeight.Bold,
        color = MaterialTheme.colorScheme.primary
    )
}

// ---- Composable with parameters ----
@Composable
fun UserCard(
    name: String,
    age: Int,
    isOnline: Boolean = false
) {
    Card(
        modifier = Modifier
            .fillMaxWidth()
            .padding(8.dp)
    ) {
        Column(
            modifier = Modifier.padding(16.dp)
        ) {
            Text(
                text = name,
                fontSize = 20.sp,
                fontWeight = FontWeight.Bold
            )
            Text(
                text = "Age: $age",
                fontSize = 16.sp
            )
            Text(
                text = if (isOnline) "🟢 Online" else "⚪ Offline",
                color = if (isOnline) Color.Green else Color.Gray
            )
        }
    }
}

// ---- Preview for development ----
@Preview(
    name = "Light Mode",
    showBackground = true
)
@Composable
fun PreviewGreeting() {
    KotlinChanTheme {
        Greeting(name = "Kotlin-chan")
    }
}

@Preview(
    name = "Dark Mode",
    uiMode = Configuration.UI_MODE_NIGHT_YES
)
@Composable
fun PreviewUserCard() {
    KotlinChanTheme {
        UserCard(
            name = "Alice",
            age = 25,
            isOnline = true
        )
    }
}

// ---- Composable with state ----
@Composable
fun Counter() {
    var count by remember { mutableStateOf(0) }

    Column(
        horizontalAlignment = Alignment.CenterHorizontally,
        modifier = Modifier.padding(16.dp)
    ) {
        Text(
            text = "Count: $count",
            fontSize = 24.sp
        )
        Button(
            onClick = { count++ }
        ) {
            Text("Increment")
        }
    }
}

