// ---- Common mistakes in Composables ----

// 1. Forgetting @Composable annotation
fun Greeting(name: String) {  // Error! Missing @Composable
    Text(text = "Hello, $name!")
}

// 2. Trying to return a value
@Composable
fun GetText(): String {  // Error! Composables don't return values
    return "Hello"
}

// 3. Using var without remember
@Composable
fun Counter() {
    var count = 0  // This will reset on every recomposition!
    Button(onClick = { count++ }) {
        Text("Count: $count")
    }
}

// 4. Calling Composable from non-Composable
fun regularFunction() {
    Greeting("Alice")  // Error! Can only be called from Composable context
}

// 5. Forgetting import
@Composable
fun MyText() {
    Text("Hello")  // Error! Text not imported
}

